DELETE FROM question_keys WHERE question_id IN (
    SELECT q.id FROM questions q JOIN passages p ON p.id = q.passage_id
    WHERE p.quiz_set_id = #{quizSetId}
)

DELETE FROM question_options WHERE question_id IN (
    SELECT q.id FROM questions q JOIN passages p ON p.id = q.passage_id
    WHERE p.quiz_set_id = #{quizSetId}
)

